const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

canvas.width = window.innerWidth;
canvas.height = window.innerHeight;

let lastTime = 0;
let playerSpeed = 5; // pixels per second

function gameLoop(currentTime) {
    const deltaTime = (currentTime - lastTime) / 1000; // seconds
    lastTime = currentTime;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Update player position based on time elapsed
    let distanceTraveled = playerSpeed * deltaTime;
    // Move player to the right (example movement)
    ctx.fillRect(playerPosition.x, playerPosition.y, 20, 20);
    playerPosition.x += distanceTraveled;

    requestAnimationFrame(gameLoop);
}

function handleInput(event) {
    if (event.key === 'ArrowRight') {
        playerSpeed = Math.min(10, playerSpeed + 1); // Cap speed at 10 pixels per second
    } else if (event.key === 'ArrowLeft') {
        playerSpeed = Math.max(2, playerSpeed - 1); // Min speed at 2 pixels per second
    }
}

const playerPosition = { x: 50, y: canvas.height / 2 };

document.addEventListener('keydown', handleInput);

requestAnimationFrame(gameLoop);